#include <cmath>
#include <iostream>

using namespace std;

/**
 * @brief Counts the total occurrences of a digit in the decimal representations of all numbers in an array.
 * 
 * @param nums An array of 64-bit integers.
 * @param digit The digit to count (0-9).
 * @return Int64 The total count.
 */
int64_t solve(const vector<int64_t>& nums, int64_t digit) {
    int64_t total_count = 0;
    char digit_char = digit + '0';

    for (int64_t num : nums) {
        // Convert the number to a string
        string s = to_string(num);

        // Count the occurrences of the digit character in the string
        int count = 0;
        for (char c : s) {
            if (c == digit_char) {
                count++;
            }
        }

        total_count += count;
    }

    return total_count;
}
