#include <stdlib.h>
#include <string.h>
#include <stdio.h>

/**
 * Counts the total occurrences of a specific digit in the decimal representations of all numbers in an array.
 *
 * @param nums The array of integers.
 * @param digit The digit to count.
 * @return The total count of the digit.
 */
int64_t solve(const int64_t nums[], int64_t digit) {
    int64_t total_count = 0;
    char digit_char = digit + '0';

    for (int i = 0; nums[i] >= 0; ++i) {
        int64_t current_num = nums[i];

        // Convert the number to a string
        char num_str[20]; // Max number is 10^6, which has 7 digits, 20 is safe
        sprintf(num_str, "%lld", current_num);

        // Count occurrences of the digit in the string
        for (int j = 0; num_str[j] != '\0'; ++j) {
            if (num_str[j] == digit_char) {
                total_count++;
            }
        }
    }

    return total_count;
}
